  AND resource_id = #{resourceId}

mapper.select:
SELECT pgr.resource_id AS resourceId, r.resource_code AS resourceCode, r.resource_name AS resourceName, r.resource_desc AS resourceDesc, r.resource_biz_type AS resourceType, r.parent_resource_id AS parentId, pgr.permission_type AS permissionType, pgr.create_by AS createBy, u.user_name AS createByName, pgr.create_time AS createTime, pgr.update_by AS updateBy, u2.user_name AS updateByName, pgr.update_time AS updateTime FROM permission_group_resources pgr LEFT JOIN ss_resource r ON pgr.resource_id = r.resource_id LEFT JOIN po_users u ON pgr.create_by = u.user_id LEFT JOIN po_users u2 ON pgr.update_by = u2.user_id WHERE pgr.permission_group_id = #{queryQO.permissionGroupId} and pgr.resource_type is null
AND pgr.resource_type = #{queryQO.resourceType}
AND r.resource_name LIKE CONCAT('%', #{queryQO.resourceName}, '%')
AND pgr.permission_type = #{queryQO.permissionType}
ORDER BY pgr.resource_id, pgr.permission_type

